(()=>{const e=document.querySelector('.menu-toggle'),t=document.querySelector('.menu-panel');if(e&&t){e.addEventListener('click',()=>{const n='true'!==e.getAttribute('aria-expanded');e.setAttribute('aria-expanded',String(n));t.hidden=!n})}document.querySelectorAll('form[data-print-form]').forEach(e=>{e.addEventListener('submit',async t=>{const n=e.querySelector('button[type="submit"]');n&&(n.disabled=!0);try{const o=await fetch(e.action,{method:'POST',body:new FormData(e),headers:{Accept:'application/json'}});if(!o.ok)throw Error('Request failed');const r=e.dataset.thanks||'/en/thanks';location.assign(r)}catch(e){alert('Please check your form and try again.')}finally{n&&(n.disabled=!1)}})})})();